//! Phase 3.5 / step 19 canonicalization test vectors.
//!
//! Each vector is `(description, ReceiptBody constructor, expected
//! canonical bytes hex, expected BLAKE3 hex)`. These commit the
//! v2 (RFC 8785 JCS) wire format to disk: any change to
//! `canonical.rs` that alters byte-level output for the same
//! logical receipt will fail at least one of these assertions.
//!
//! The same logical bodies are also exposed as a JSON fixture
//! for cross-language verifier conformance — see
//! `tests/vectors/canonical-v2.json` (auto-generated by the
//! `dump_canonical_vectors_to_file` test below).
//!
//! Adding a vector:
//! 1. Build the `ReceiptBody` in [`vector_bodies`].
//! 2. Run `cargo test -p uniclaw-receipt --test vectors -- --nocapture
//!    print_vectors` to print the (`canonical_hex`, `blake3_hex`) for
//!    the new vector.
//! 3. Paste those values into [`expected_outputs`] alongside the
//!    body's index.
//! 4. Re-run; the snapshot test passes.

use uniclaw_receipt::{
    Action, Decision, Digest, MerkleLeaf, ProvenanceEdge, RECEIPT_FORMAT_VERSION, ReceiptBody,
    RuleRef,
};

fn vector_bodies() -> Vec<(&'static str, ReceiptBody)> {
    vec![
        (
            "minimal-allowed",
            ReceiptBody {
                schema_version: RECEIPT_FORMAT_VERSION,
                issued_at: "2026-04-26T12:00:00Z".into(),
                action: Action {
                    kind: "http.fetch".into(),
                    target: "https://example.com/".into(),
                    input_hash: Digest([0u8; 32]),
                },
                decision: Decision::Allowed,
                constitution_rules: vec![],
                provenance: vec![],
                redactor_stack_hash: None,
                key_id: None,
                merkle_leaf: MerkleLeaf {
                    sequence: 0,
                    leaf_hash: Digest([1u8; 32]),
                    prev_hash: Digest([0u8; 32]),
                },
            },
        ),
        (
            "denied-with-rule",
            ReceiptBody {
                schema_version: RECEIPT_FORMAT_VERSION,
                issued_at: "2026-04-26T12:00:01Z".into(),
                action: Action {
                    kind: "shell.exec".into(),
                    target: "rm -rf /".into(),
                    input_hash: Digest([2u8; 32]),
                },
                decision: Decision::Denied,
                constitution_rules: vec![RuleRef {
                    id: "solo-dev/no-shell".into(),
                    matched: true,
                }],
                provenance: vec![],
                redactor_stack_hash: None,
                key_id: None,
                merkle_leaf: MerkleLeaf {
                    sequence: 1,
                    leaf_hash: Digest([3u8; 32]),
                    prev_hash: Digest([1u8; 32]),
                },
            },
        ),
        (
            "with-provenance-edges",
            ReceiptBody {
                schema_version: RECEIPT_FORMAT_VERSION,
                issued_at: "2026-04-26T12:00:02Z".into(),
                action: Action {
                    kind: "tool.http_fetch".into(),
                    target: "https://api.github.com/user".into(),
                    input_hash: Digest([4u8; 32]),
                },
                decision: Decision::Allowed,
                constitution_rules: vec![],
                provenance: vec![
                    ProvenanceEdge {
                        from: "user".into(),
                        to: "model".into(),
                        kind: "request".into(),
                    },
                    ProvenanceEdge {
                        from: "model".into(),
                        to: "tool:http_fetch".into(),
                        kind: "tool_call".into(),
                    },
                ],
                redactor_stack_hash: None,
                key_id: None,
                merkle_leaf: MerkleLeaf {
                    sequence: 2,
                    leaf_hash: Digest([5u8; 32]),
                    prev_hash: Digest([3u8; 32]),
                },
            },
        ),
        (
            "with-redactor-stack-hash",
            ReceiptBody {
                schema_version: RECEIPT_FORMAT_VERSION,
                issued_at: "2026-04-26T12:00:03Z".into(),
                action: Action {
                    kind: "$kernel/tool/executed".into(),
                    target: "tool=http_fetch status=ok".into(),
                    input_hash: Digest([0u8; 32]),
                },
                decision: Decision::Allowed,
                constitution_rules: vec![],
                provenance: vec![ProvenanceEdge {
                    from: "receipt:00".into(),
                    to: "redaction:default::github_pat:count=1".into(),
                    kind: "redaction_applied".into(),
                }],
                redactor_stack_hash: Some(Digest([0xAB; 32])),
                key_id: None,
                merkle_leaf: MerkleLeaf {
                    sequence: 3,
                    leaf_hash: Digest([6u8; 32]),
                    prev_hash: Digest([5u8; 32]),
                },
            },
        ),
        (
            "pending-approval",
            ReceiptBody {
                schema_version: RECEIPT_FORMAT_VERSION,
                issued_at: "2026-04-26T12:00:04Z".into(),
                action: Action {
                    kind: "git.push".into(),
                    target: "origin/main".into(),
                    input_hash: Digest([7u8; 32]),
                },
                decision: Decision::Pending,
                constitution_rules: vec![RuleRef {
                    id: "solo-dev/git-push-approval".into(),
                    matched: true,
                }],
                provenance: vec![],
                redactor_stack_hash: None,
                key_id: None,
                merkle_leaf: MerkleLeaf {
                    sequence: 4,
                    leaf_hash: Digest([8u8; 32]),
                    prev_hash: Digest([6u8; 32]),
                },
            },
        ),
        // Step 19a: a Allowed receipt where the kernel's signer
        // identifies itself with `key_id = "prod-2026"`. The new
        // field is sorted into JCS output between `issued_at` and
        // `merkle_leaf` (lexicographic).
        (
            "with-key-id-prod-2026",
            ReceiptBody {
                schema_version: RECEIPT_FORMAT_VERSION,
                issued_at: "2026-04-26T12:00:05Z".into(),
                action: Action {
                    kind: "http.fetch".into(),
                    target: "https://example.com/with-key-id".into(),
                    input_hash: Digest([9u8; 32]),
                },
                decision: Decision::Allowed,
                constitution_rules: vec![],
                provenance: vec![],
                redactor_stack_hash: None,
                key_id: Some("prod-2026".into()),
                merkle_leaf: MerkleLeaf {
                    sequence: 5,
                    leaf_hash: Digest([0x9a; 32]),
                    prev_hash: Digest([8u8; 32]),
                },
            },
        ),
        // Step 19a: a tool-execution receipt where the kernel
        // signed with `key_id = "hsm-3"`. Exercises the field
        // alongside `redactor_stack_hash` and a provenance edge.
        (
            "tool-execution-with-key-id-hsm-3",
            ReceiptBody {
                schema_version: RECEIPT_FORMAT_VERSION,
                issued_at: "2026-04-26T12:00:06Z".into(),
                action: Action {
                    kind: "$kernel/tool/executed".into(),
                    target: "tool=http_fetch status=ok".into(),
                    input_hash: Digest([0u8; 32]),
                },
                decision: Decision::Allowed,
                constitution_rules: vec![],
                provenance: vec![ProvenanceEdge {
                    from: "receipt:9a".into(),
                    to: "tool:http_fetch".into(),
                    kind: "tool_execution".into(),
                }],
                redactor_stack_hash: None,
                key_id: Some("hsm-3".into()),
                merkle_leaf: MerkleLeaf {
                    sequence: 6,
                    leaf_hash: Digest([0xb1; 32]),
                    prev_hash: Digest([0x9a; 32]),
                },
            },
        ),
    ]
}

