/// Print the canonical-bytes and BLAKE3 for every vector. Used to
/// (re)generate [`expected_outputs`]. Doesn't assert; running this
/// is how you produce the table.
#[test]
#[ignore = "regenerator: produces test-vector pairs to paste back"]
fn print_vectors() {
    for (i, (name, body)) in vector_bodies().iter().enumerate() {
        let canonical = uniclaw_receipt::canonical::to_vec(body).unwrap();
        let hash = blake3::hash(&canonical);
        println!(
            "// [{i}] {name}\n(\"{}\", \"{}\"),",
            hex_encode(&canonical),
            hex_encode(hash.as_bytes()),
        );
    }
}

/// The actual snapshot test. Compares each vector's canonical
/// bytes + BLAKE3 against the pinned values in
/// [`expected_outputs`]. Skipped when `expected_outputs` is still
/// the placeholder ("`REGEN_ME`") — rerun `print_vectors` and
/// paste in real values.
#[test]
fn vectors_match_expected_canonical_and_hash() {
    let bodies = vector_bodies();
    let expected = expected_outputs();
    assert_eq!(
        bodies.len(),
        expected.len(),
        "vector list lengths must match"
    );

    for (i, ((name, body), (exp_canonical_hex, exp_hash_hex))) in
        bodies.iter().zip(expected.iter()).enumerate()
    {
        if *exp_canonical_hex == "REGEN_ME" {
            eprintln!("[{i}] {name}: SKIP (placeholder; run print_vectors and paste back)");
            continue;
        }
        let canonical = uniclaw_receipt::canonical::to_vec(body).unwrap();
        let canonical_hex = hex_encode(&canonical);
        let hash = blake3::hash(&canonical);
        let hash_hex = hex_encode(hash.as_bytes());

        assert_eq!(
            canonical_hex, *exp_canonical_hex,
            "[{i}] {name}: canonical bytes diverged",
        );
        assert_eq!(hash_hex, *exp_hash_hex, "[{i}] {name}: hash diverged");
    }
}

/// Auto-generate (or refresh) the JSON fixture file under
/// `tests/vectors/canonical-v2.json` from the current bodies +
/// the canonicalizer's output. The fixture is what cross-language
/// verifiers (TypeScript browser verifier, future Go/Python ports)
/// load to confirm they produce identical bytes.
///
/// `#[ignore]` so it doesn't run in the normal test sweep — the
/// fixture is committed and changes only when canonicalization
/// changes, in which case the operator runs this manually.
#[test]
#[ignore = "regenerator: writes tests/vectors/canonical-v2.json"]
fn dump_canonical_vectors_to_file() {
    use std::fmt::Write as FmtWrite;
    use std::io::Write as IoWrite;
    let path = std::path::Path::new(env!("CARGO_MANIFEST_DIR"))
        .join("tests")
        .join("vectors")
        .join("canonical-v2.json");
    std::fs::create_dir_all(path.parent().unwrap()).unwrap();

    let mut out = String::new();
    out.push_str("{\n  \"format\": \"uniclaw-canonical-v2\",\n  \"vectors\": [\n");
    for (i, (name, body)) in vector_bodies().iter().enumerate() {
        let canonical = uniclaw_receipt::canonical::to_vec(body).unwrap();
        let hash = blake3::hash(&canonical);
        let body_pretty = serde_json::to_string(body).unwrap();
        if i > 0 {
            out.push_str(",\n");
        }
        let _ = write!(
            out,
            "    {{\n      \"name\": \"{name}\",\n      \"body\": {body_pretty},\n      \"canonical_hex\": \"{}\",\n      \"blake3_hex\": \"{}\"\n    }}",
            hex_encode(&canonical),
            hex_encode(hash.as_bytes()),
        );
    }
    out.push_str("\n  ]\n}\n");

    let mut f = std::fs::File::create(&path).unwrap();
    f.write_all(out.as_bytes()).unwrap();
    println!(
        "wrote {} ({} vectors)",
        path.display(),
        vector_bodies().len()
    );
}

fn hex_encode(bytes: &[u8]) -> String {
    use std::fmt::Write;
    let mut s = String::with_capacity(bytes.len() * 2);
    for b in bytes {
        let _ = write!(s, "{b:02x}");
    }
    s
}
